module top_module(
    input A,
    output Z,
    input TE,
    input VPB,
    input VPWR,
    input VGND,
    input VNB
);reg inv_Z_reg;

    always @(*) begin
        if (VGND >= VPWR) begin
            inv_Z_reg = ~A;
        end else if (TE == 1) begin
            inv_Z_reg = ~A;
        end else begin
            inv_Z_reg = A;
        end
    end

    assign Z = inv_Z_reg;

endmodule
